svg.script:
(function () {
  var D = [
    'M80,92 C240,92 480,93 700,93',
    'M80,96 C160,97 220,99 267,102 C310,105 350,116 391,126 C433,140 470,163 516,176 C560,189 640,206 700,214',
    'M80,98 C130,102 170,107 204,114 C230,120 248,126 267,134 C300,148 350,180 391,196 C440,212 560,228 700,234'
  ];
  var MX  = [700, 405, 258], MY1 = [92, 130, 130];
  var MTX = [694, 411, 264], MTA = ['end', 'start', 'start'];
  var MTT = ['effective ≈ advertised', 'effective context', 'effective context'];
  var AX  = [700, 516, 391], AY = [92, 176, 196], ATX = [690, 506, 383], ATY = [112, 194, 216];
  var ATT = ['≈100% recall at 1M', '~57% at 128K', 'below half of baseline by 32K'];
  var EX  = [
    'One planted fact, recited back — near-perfect all the way to 1M. Saturated: the entry ticket, not the proof.',
    'Two needles to tell apart instead of one — holds, then falls hard: ~57% by 128K.',
    'No shared words to match — the model must actually reason: below half its baseline by 32K.'
  ];
  var cv = document.getElementById('cv'), ml = document.getElementById('ml'),
      md = document.getElementById('md'), mt = document.getElementById('mt'),
      ac = document.getElementById('ac'), at = document.getElementById('at'),
      ex = document.getElementById('ex');
  function set(m) {
    cv.setAttribute('d', D[m]);
    ml.setAttribute('x1', MX[m]); ml.setAttribute('x2', MX[m]); ml.setAttribute('y1', MY1[m]);
    md.setAttribute('cx', MX[m]); md.setAttribute('cy', MY1[m]);
    mt.setAttribute('x', MTX[m]); mt.setAttribute('text-anchor', MTA[m]); mt.textContent = MTT[m];
    ac.setAttribute('cx', AX[m]); ac.setAttribute('cy', AY[m]);
    at.setAttribute('x', ATX[m]); at.setAttribute('y', ATY[m]); at.textContent = ATT[m];
    ex.textContent = EX[m];
    for (var k = 0; k < 3; k++) {
      document.getElementById('tr' + k).setAttribute('stroke', k === m ? '#1b1b1a' : '#ececec');
      document.getElementById('tt' + k).setAttribute('font-weight', k === m ? '700' : '400');
    }
  }
  for (var k = 0; k < 3; k++) (function (m) {
    document.getElementById('tb' + m).addEventListener('click', function () { set(m); });
  })(k);
})();
